protected void defaultLineAmount(VendInvoiceInfoLine _vendInvoiceInfoLine)
{

    VendInvoiceInfoLine        locinvline;
    PurchParmLine               ppline;


    select forupdate locinvline where locinvline.RecId == _vendInvoiceInfoLine.RecId;
    if(locinvline)
    {
        select ppline where ppline.PurchLineRecId == locinvline.PurchLineRecId
            && ppline.InventTransId == locinvline.InventTransId;
        if(ppline)
        {
           // ttsbegin;
            _vendInvoiceInfoLine.PurchPrice = ppline.PurchPrice;
            _vendInvoiceInfoLine.LineAmount = ppline.LineAmount;
          //  _vendInvoiceInfoLine.update();

          //  ttscommit;
        }

    }
    next defaultLineAmount(_vendInvoiceInfoLine);

}

/// <summary>
/// Adds <c>VendPackingSlipTrans</c> table specific fields to the insert field mappings.
/// </summary>
/// <param name = "_queryBuildDataSource">The given <c>QueryBuildDataSource</c> used for the field mapping.</param>
/// <param name = "_queryBuildFieldList">The given <c>QueryBuildFieldList</c> instance in which to add the field mapping.</param>
/// <param name = "_insertRecordsetMap">The given <c>Map</c> instance in which to add the field mapping.</param>
protected void addFieldMappingsVendPackingSlipTrans(QueryBuildDataSource _queryBuildDataSource, QueryBuildFieldList _queryBuildFieldList, Map _insertRecordsetMap)
{
    next addFieldMappingsVendPackingSlipTrans(_queryBuildDataSource, _queryBuildFieldList, _insertRecordsetMap);

    int dataSourceUniqueId = _queryBuildDataSource.uniqueId();
    this.addInsertFieldMapping(_queryBuildFieldList, _insertRecordsetMap, dataSourceUniqueId, fieldNum(VendPackingSlipTrans, BOLDate), fieldStr(VendPackingSlipTrans, BOLDate), fieldStr(VendInvoiceInfoSubLine, ETG_BLDate));
    this.addInsertFieldMapping(_queryBuildFieldList, _insertRecordsetMap, dataSourceUniqueId, fieldNum(VendPackingSlipTrans, BOLNo), fieldStr(VendPackingSlipTrans, BOLNo), fieldStr(VendInvoiceInfoSubLine, ETG_BLnumber));
}
